 122	static int match_skip(bparser *parser, btokentype type)
 123	{
 124	    if (next_type(parser) == type) { /* match */
 125	        scan_next_token(parser); /* skip this token */
 126	        return btrue;
 127	    }
 128	    return bfalse;
 129	}
