 156	void end_varinfo(bparser *parser, int beginpc)
 157	{
 158	    bfuncinfo *finfo = parser->finfo;
 159	    bblockinfo *binfo = finfo->binfo;
 160	    bvarinfo *it = be_vector_data(&finfo->varvec);
 161	    bvarinfo *end = be_vector_end(&finfo->varvec);
 162	    if (beginpc == -1) /* use block->beginpc by default */
 163	        beginpc = binfo->beginpc;
 164	    /* skip the variable of the previous blocks */
 165	    for (; it->beginpc < beginpc; ++it);
 166	    for (; it <= end; ++it) {
 167	        if (!it->endpc) /* write to endpc only once */
 168	            it->endpc = finfo->pc;
 169	    }
 170	}
